SourceCode.Declaration:
/// <summary>
/// Data contract for the "Customer Aging with Bank" report. Carries the as-of date
/// used by the data provider to build the aging buckets and bank balances.
/// </summary>
[DataContractAttribute]
class BCRCustomerAgingwithBankContract
{
    TransDate   FromDate;

}

Method.Source:
/// <summary>
/// Gets or sets the as-of date for the aging calculation.
/// </summary>
/// <param name="_FromDate">The as-of date to set; defaults to the current value.</param>
/// <returns>The current as-of date.</returns>
[DataMemberAttribute('From date'),
   SysOperationLabelAttribute(literalStr("Date")),
   SysOperationDisplayOrderAttribute('1')]
public TransDate ParmFromDate(TransDate _FromDate = FromDate)
{
    FromDate = _FromDate;
    return FromDate;
}
